const e=JSON.parse('{"key":"v-129629ec","path":"/posts/%E6%A8%A1%E5%9D%97%E8%AE%BE%E8%AE%A1/22%E3%80%81%E5%A4%9A%E8%B7%AF%E5%8F%AC%E5%9B%9E.html","title":"多路召回","lang":"en-US","frontmatter":{"icon":"pen-to-square","date":"2025-11-27T00:00:00.000Z","category":["RAG"],"tag":["多路召回"],"description":"多路召回 “多路召回+重排序”是RAG检索层的核心优化策略，本质是“多渠道获取检索结果，再通过模型筛选最优结果”，解决单一召回通道的局限性；多路召回指通过多个不同的召回通道（向量、关键词、知识图谱），分别获取与用户查询相关的结果；重排序指将多个通道的结果合并，通过模型对结果进行打分排序，筛选出最贴合用户需求的TopN结果，作为大模型的输入。 一、为什么需要多路召回 单一召回通道存在明显缺陷： 向量召回擅长语义匹配，但对专业术语、关键词的精准匹配不足； 关键词召回擅长精准匹配专业术语，但无法捕捉语义相似性； 知识图谱召回擅长实体关联检索，但对非结构化文本的适配性弱。","head":[["meta",{"property":"og:url","content":"https://y-aong.github.io/orderlines_blog/orderlines_blog/posts/%E6%A8%A1%E5%9D%97%E8%AE%BE%E8%AE%A1/22%E3%80%81%E5%A4%9A%E8%B7%AF%E5%8F%AC%E5%9B%9E.html"}],["meta",{"property":"og:site_name","content":"ORDERLINES"}],["meta",{"property":"og:title","content":"多路召回"}],["meta",{"property":"og:description","content":"多路召回 “多路召回+重排序”是RAG检索层的核心优化策略，本质是“多渠道获取检索结果，再通过模型筛选最优结果”，解决单一召回通道的局限性；多路召回指通过多个不同的召回通道（向量、关键词、知识图谱），分别获取与用户查询相关的结果；重排序指将多个通道的结果合并，通过模型对结果进行打分排序，筛选出最贴合用户需求的TopN结果，作为大模型的输入。 一、为什么需要多路召回 单一召回通道存在明显缺陷： 向量召回擅长语义匹配，但对专业术语、关键词的精准匹配不足； 关键词召回擅长精准匹配专业术语，但无法捕捉语义相似性； 知识图谱召回擅长实体关联检索，但对非结构化文本的适配性弱。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2026-04-06T15:14:04.000Z"}],["meta",{"property":"article:author","content":"Y-aong"}],["meta",{"property":"article:tag","content":"多路召回"}],["meta",{"property":"article:published_time","content":"2025-11-27T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2026-04-06T15:14:04.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"多路召回\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2025-11-27T00:00:00.000Z\\",\\"dateModified\\":\\"2026-04-06T15:14:04.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Y-aong\\",\\"url\\":\\"https://github.com/Y-aong\\"}]}"]]},"headers":[{"level":3,"title":"一、为什么需要多路召回","slug":"一、为什么需要多路召回","link":"#一、为什么需要多路召回","children":[]},{"level":3,"title":"二、召回通道设计","slug":"二、召回通道设计","link":"#二、召回通道设计","children":[]},{"level":3,"title":"三、结果融合逻辑","slug":"三、结果融合逻辑","link":"#三、结果融合逻辑","children":[]},{"level":3,"title":"四、重排序模型的选择","slug":"四、重排序模型的选择","link":"#四、重排序模型的选择","children":[]}],"git":{"createdTime":1775441287000,"updatedTime":1775488444000,"contributors":[{"name":"Y-aong","email":"1627469727@qq.com","commits":2}]},"readingTime":{"minutes":7.95,"words":2386},"filePathRelative":"posts/模块设计/22、多路召回.md","localizedDate":"November 27, 2025","excerpt":"<h1> 多路召回</h1>\\n<p>“<strong>多路召回+重排序</strong>”是RAG检索层的核心优化策略，本质是“多渠道获取检索结果，再通过模型筛选最优结果”，解决单一召回通道的局限性；多路召回指通过多个不同的召回通道（向量、关键词、知识图谱），分别获取与用户查询相关的结果；重排序指将多个通道的结果合并，通过模型对结果进行打分排序，筛选出最贴合用户需求的TopN结果，作为大模型的输入。</p>\\n<h3> 一、为什么需要多路召回</h3>\\n<p>单一召回通道存在明显缺陷：</p>\\n<ul>\\n<li>向量召回擅长语义匹配，但对专业术语、关键词的精准匹配不足；</li>\\n<li>关键词召回擅长精准匹配专业术语，但无法捕捉语义相似性；</li>\\n<li>知识图谱召回擅长实体关联检索，但对非结构化文本的适配性弱。</li>\\n</ul>","autoDesc":true}');export{e as data};
